  <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Liquidación de Nómina Comparada: Lote ACH vs. Riel USA₮</text>
  <g font-family="sans-serif">
    <rect x="20" y="54" width="310" height="310" rx="10" fill="#14283f" stroke="#38bdf8" stroke-width="1.6"/>
    <text x="175" y="86" fill="#7dd3fc" text-anchor="middle" font-size="14" font-weight="800">Liquidación por Lotes ACH</text>
    <text x="40" y="118" fill="#e4e4e7" font-size="13">Ciclo: ligado a días bancarios</text>
